import React, { useState, useEffect } from 'react';

const API_URL = process.env.REACT_APP_API_URL || 'http://localhost:5000';

const formatDate = (iso) => new Date(iso).toLocaleDateString('fr-FR', {
  day: 'numeric', month: 'long', year: 'numeric'
});

const getFileIcon = (mimetype) => {
  if (!mimetype) return '📄';
  if (mimetype.includes('pdf')) return '📕';
  if (mimetype.includes('image')) return '🖼️';
  if (mimetype.includes('word') || mimetype.includes('doc')) return '📘';
  return '📄';
};

export default function Blog() {
  const [articles, setArticles] = useState([]);
  const [categories, setCategories] = useState(['Tous']);
  const [activeCategory, setActiveCategory] = useState('Tous');
  const [search, setSearch] = useState('');
  const [loading, setLoading] = useState(true);
  const [selected, setSelected] = useState(null);

  useEffect(() => {
    fetchCategories();
    fetchArticles();
  }, []);

  useEffect(() => {
    fetchArticles();
  }, [activeCategory, search]);

  const fetchArticles = async () => {
    setLoading(true);
    try {
      const params = new URLSearchParams();
      if (activeCategory !== 'Tous') params.append('category', activeCategory);
      if (search) params.append('search', search);
      const res = await fetch(`${API_URL}/api/articles?${params}`);
      const data = await res.json();
      setArticles(data);
    } catch (err) {
      console.error('Erreur chargement articles:', err);
    } finally {
      setLoading(false);
    }
  };

  const fetchCategories = async () => {
    try {
      const res = await fetch(`${API_URL}/api/categories`);
      const data = await res.json();
      setCategories(data);
    } catch (err) {}
  };

  const styles = {
    page: {
      minHeight: '100vh',
      background: '#0a0f0a',
      color: '#e8e8e8',
      fontFamily: "'Segoe UI', sans-serif",
      paddingTop: '80px',
    },
    hero: {
      textAlign: 'center',
      padding: '60px 20px 40px',
      background: 'linear-gradient(180deg, rgba(0,180,0,0.07) 0%, transparent 100%)',
    },
    heroTitle: {
      fontSize: 'clamp(2rem, 5vw, 3.5rem)',
      fontWeight: 800,
      color: '#ffd700',
      margin: '0 0 10px',
      letterSpacing: '-1px',
    },
    heroSub: {
      color: '#00aa00',
      fontSize: '1.1rem',
      marginBottom: '40px',
    },
    searchBar: {
      display: 'flex',
      maxWidth: '500px',
      margin: '0 auto',
      background: 'rgba(255,255,255,0.05)',
      border: '1px solid rgba(0,200,0,0.3)',
      borderRadius: '12px',
      overflow: 'hidden',
    },
    searchInput: {
      flex: 1,
      background: 'transparent',
      border: 'none',
      outline: 'none',
      padding: '14px 20px',
      color: '#e8e8e8',
      fontSize: '1rem',
    },
    searchBtn: {
      background: '#00bb00',
      border: 'none',
      padding: '14px 20px',
      cursor: 'pointer',
      fontSize: '1.1rem',
    },
    container: {
      maxWidth: '1200px',
      margin: '0 auto',
      padding: '0 20px 60px',
    },
    categoryBar: {
      display: 'flex',
      gap: '10px',
      flexWrap: 'wrap',
      marginBottom: '40px',
      justifyContent: 'center',
    },
    catBtn: (active) => ({
      background: active ? '#ffd700' : 'rgba(255,215,0,0.1)',
      color: active ? '#0a0f0a' : '#ffd700',
      border: '1px solid rgba(255,215,0,0.3)',
      borderRadius: '30px',
      padding: '8px 20px',
      cursor: 'pointer',
      fontWeight: active ? 700 : 400,
      fontSize: '0.9rem',
      transition: 'all 0.2s',
    }),
    grid: {
      display: 'grid',
      gridTemplateColumns: 'repeat(auto-fill, minmax(340px, 1fr))',
      gap: '24px',
    },
    card: {
      background: 'rgba(255,255,255,0.03)',
      border: '1px solid rgba(0,200,0,0.15)',
      borderRadius: '16px',
      overflow: 'hidden',
      cursor: 'pointer',
      transition: 'all 0.3s',
    },
    cardInner: {
      padding: '24px',
    },
    cardCategory: {
      display: 'inline-block',
      background: 'rgba(0,187,0,0.15)',
      color: '#00cc00',
      borderRadius: '20px',
      padding: '4px 12px',
      fontSize: '0.78rem',
      fontWeight: 600,
      marginBottom: '12px',
      textTransform: 'uppercase',
      letterSpacing: '0.5px',
    },
    cardTitle: {
      fontSize: '1.25rem',
      fontWeight: 700,
      color: '#ffd700',
      marginBottom: '10px',
      lineHeight: 1.3,
    },
    cardDesc: {
      color: '#aaa',
      fontSize: '0.9rem',
      lineHeight: 1.6,
      marginBottom: '16px',
    },
    cardMeta: {
      display: 'flex',
      justifyContent: 'space-between',
      alignItems: 'center',
      color: '#666',
      fontSize: '0.8rem',
      borderTop: '1px solid rgba(255,255,255,0.05)',
      paddingTop: '12px',
    },
    fileTag: {
      background: 'rgba(255,215,0,0.1)',
      border: '1px solid rgba(255,215,0,0.2)',
      borderRadius: '8px',
      padding: '4px 10px',
      color: '#ffd700',
      fontSize: '0.78rem',
    },
    empty: {
      textAlign: 'center',
      padding: '80px 20px',
      color: '#555',
    },
    // Modal
    overlay: {
      position: 'fixed',
      inset: 0,
      background: 'rgba(0,0,0,0.85)',
      zIndex: 1000,
      display: 'flex',
      alignItems: 'flex-start',
      justifyContent: 'center',
      overflowY: 'auto',
      padding: '40px 20px',
    },
    modal: {
      background: '#0f1a0f',
      border: '1px solid rgba(0,200,0,0.2)',
      borderRadius: '20px',
      maxWidth: '750px',
      width: '100%',
      padding: '40px',
      position: 'relative',
    },
    modalClose: {
      position: 'absolute',
      top: '20px',
      right: '20px',
      background: 'rgba(255,255,255,0.1)',
      border: 'none',
      color: '#fff',
      width: '36px',
      height: '36px',
      borderRadius: '50%',
      cursor: 'pointer',
      fontSize: '1.1rem',
    },
    downloadBtn: {
      display: 'inline-flex',
      alignItems: 'center',
      gap: '8px',
      background: 'linear-gradient(135deg, #00bb00, #007700)',
      color: '#fff',
      textDecoration: 'none',
      borderRadius: '10px',
      padding: '12px 24px',
      fontWeight: 600,
      marginTop: '20px',
    }
  };

  return (
    <div style={styles.page}>
      {/* Hero */}
      <div style={styles.hero}>
        <h1 style={styles.heroTitle}>🔥 Blog BBRS Morphix IT</h1>
        <p style={styles.heroSub}>Ressources, guides et actualités informatiques</p>
        <div style={styles.searchBar}>
          <input
            style={styles.searchInput}
            placeholder="Rechercher un article..."
            value={search}
            onChange={e => setSearch(e.target.value)}
            onKeyDown={e => e.key === 'Enter' && fetchArticles()}
          />
          <button style={styles.searchBtn} onClick={fetchArticles}>🔍</button>
        </div>
      </div>

      <div style={styles.container}>
        {/* Catégories */}
        <div style={styles.categoryBar}>
          {categories.map(cat => (
            <button
              key={cat}
              style={styles.catBtn(activeCategory === cat)}
              onClick={() => setActiveCategory(cat)}
            >
              {cat}
            </button>
          ))}
        </div>

        {/* Grille articles */}
        {loading ? (
          <div style={styles.empty}>
            <div style={{ fontSize: '2rem', marginBottom: '10px' }}>⏳</div>
            Chargement des articles...
          </div>
        ) : articles.length === 0 ? (
          <div style={styles.empty}>
            <div style={{ fontSize: '3rem', marginBottom: '10px' }}>📭</div>
            <p>Aucun article pour le moment.</p>
          </div>
        ) : (
          <div style={styles.grid}>
            {articles.map(article => (
              <div
                key={article.id}
                style={styles.card}
                onClick={() => setSelected(article)}
                onMouseEnter={e => {
                  e.currentTarget.style.transform = 'translateY(-4px)';
                  e.currentTarget.style.borderColor = 'rgba(0,200,0,0.4)';
                  e.currentTarget.style.boxShadow = '0 12px 40px rgba(0,150,0,0.15)';
                }}
                onMouseLeave={e => {
                  e.currentTarget.style.transform = 'translateY(0)';
                  e.currentTarget.style.borderColor = 'rgba(0,200,0,0.15)';
                  e.currentTarget.style.boxShadow = 'none';
                }}
              >
                <div style={styles.cardInner}>
                  <span style={styles.cardCategory}>{article.category}</span>
                  <h3 style={styles.cardTitle}>{article.title}</h3>
                  {article.description && (
                    <p style={styles.cardDesc}>
                      {article.description.length > 120
                        ? article.description.slice(0, 120) + '...'
                        : article.description}
                    </p>
                  )}
                  <div style={styles.cardMeta}>
                    <span>📅 {formatDate(article.createdAt)}</span>
                    <span>✍️ {article.author}</span>
                    {article.file && (
                      <span style={styles.fileTag}>
                        {getFileIcon(article.file.mimetype)} Fichier joint
                      </span>
                    )}
                  </div>
                </div>
              </div>
            ))}
          </div>
        )}
      </div>

      {/* Modal article */}
      {selected && (
        <div style={styles.overlay} onClick={() => setSelected(null)}>
          <div style={styles.modal} onClick={e => e.stopPropagation()}>
            <button style={styles.modalClose} onClick={() => setSelected(null)}>✕</button>
            <span style={styles.cardCategory}>{selected.category}</span>
            <h2 style={{ color: '#ffd700', fontSize: '1.8rem', margin: '10px 0 8px' }}>
              {selected.title}
            </h2>
            <div style={{ color: '#555', fontSize: '0.85rem', marginBottom: '20px' }}>
              📅 {formatDate(selected.createdAt)} · ✍️ {selected.author}
            </div>
            {selected.description && (
              <p style={{ color: '#ccc', fontSize: '1rem', lineHeight: 1.7, marginBottom: '16px' }}>
                {selected.description}
              </p>
            )}
            {selected.content && (
              <div style={{
                background: 'rgba(255,255,255,0.03)',
                borderRadius: '12px',
                padding: '20px',
                color: '#bbb',
                lineHeight: 1.8,
                whiteSpace: 'pre-wrap',
                fontSize: '0.95rem',
              }}>
                {selected.content}
              </div>
            )}
            {selected.file && (
              <a
                href={`${API_URL}${selected.file.url}`}
                target="_blank"
                rel="noreferrer"
                style={styles.downloadBtn}
              >
                {getFileIcon(selected.file.mimetype)} Télécharger — {selected.file.originalname}
              </a>
            )}
          </div>
        </div>
      )}
    </div>
  );
}
